import{_ as m}from"./plugin-vue_export-helper-DlAUqK2U.js";import{r as t,o as h,c as w,a as n,t as v,b as a,w as p,n as i,g as c,d as s,e as l}from"./app-BVWDC1Tu.js";const f={},g={id:"frontmatter-title-관련",tabindex:"-1"},b={class:"header-anchor",href:"#frontmatter-title-관련"},y={class:"table-of-contents"},q=n("hr",null,null,-1),S=n("h2",{id:"project-12-part-1",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#project-12-part-1"},[n("span",null,"Project 12, part 1")])],-1),x=n("p",null,"In this technique project we’re going to explore how SwiftData and SwiftUI work together to help us build great apps. I already introduced you to the topic in project 11, but here we’re going to be going into more detail: custom managed object subclasses, ensuring uniqueness, and more.",-1),D=n("p",null,"American entrepreneur Jim Rohn once said, “success is neither magical nor mysterious – success is the natural consequence of consistently applying the basic fundamentals.” SwiftData is absolutely one of those basic fundamentals – you certainly won’t use it in every project, but understanding how it works and how to make the most of it will make you a better app developer.",-1),_=n("p",null,[n("strong",null,[s("Today you have three topics to work through, in which you’ll learn how to edit SwiftData objects with SwiftUI, and also how to filter your data using "),n("code",null,"#Predicate"),s(", and more.")])],-1),j=n("h3",{id:"swiftdata-introduction",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#swiftdata-introduction"},[n("span",null,"SwiftData: Introduction")])],-1),U=n("p",null,"::: detail SwiftData: Introduction",-1),I=l('<p>This technique project is going to explore SwiftData in more detail, starting with a summary of some basic techniques then building up to tackling some more complex problems.</p><p>As you&#39;ll see, SwiftData really pushes hard on advanced features of both Swift and SwiftUI, all to help make it easy for us to store data efficiently. It&#39;s not always easy, though, and there are a few places that take quite a bit of thinking to use properly.</p><p>We have lots to explore, so please create a fresh project where we can try it out. Call it “SwiftDataProject” and not just “SwiftData” because that will cause Xcode to get confused.</p><p><strong>Make sure you do not enable SwiftData for storage.</strong> Again, we&#39;ll be building this from scratch so you can see how it all works.</p><p>All set? Let’s go!</p><p>:::</p><h3 id="editing-swiftdata-model-objects" tabindex="-1"><a class="header-anchor" href="#editing-swiftdata-model-objects"><span>Editing SwiftData model objects</span></a></h3><p>::: detail Editing SwiftData model objects</p>',8),T=n("p",null,[s("SwiftData's model objects are powered by the same observation system that makes "),n("code",null,"@Observable"),s(" classes work, which means changes to your model objects are automatically picked up by SwiftUI so that our data and our user interface stay in sync.")],-1),C=n("p",null,[s("This support extends to the "),n("code",null,"@Bindable"),s(" property wrapper we looked at previously, which means we get delightfully straightforward object editing.")],-1),P=n("code",null,"User",-1),R=n("code",null,"User.swift",-1),E=l(`<div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token attribute atrule">@Model</span>
<span class="token keyword">class</span> <span class="token class-name">User</span> <span class="token punctuation">{</span>
    <span class="token keyword">var</span> name<span class="token punctuation">:</span> <span class="token class-name">String</span>
    <span class="token keyword">var</span> city<span class="token punctuation">:</span> <span class="token class-name">String</span>
    <span class="token keyword">var</span> joinDate<span class="token punctuation">:</span> <span class="token class-name">Date</span>

    <span class="token keyword">init</span><span class="token punctuation">(</span>name<span class="token punctuation">:</span> <span class="token class-name">String</span><span class="token punctuation">,</span> city<span class="token punctuation">:</span> <span class="token class-name">String</span><span class="token punctuation">,</span> joinDate<span class="token punctuation">:</span> <span class="token class-name">Date</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">self</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name
        <span class="token keyword">self</span><span class="token punctuation">.</span>city <span class="token operator">=</span> city
        <span class="token keyword">self</span><span class="token punctuation">.</span>joinDate <span class="token operator">=</span> joinDate
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Now we can create a model container and model context for that by adding another <code>import SwiftData</code> in the <code>App</code> struct file then using <code>modelContainer()</code> like this:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token class-name">WindowGroup</span> <span class="token punctuation">{</span>
    <span class="token class-name">ContentView</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
<span class="token punctuation">.</span><span class="token function">modelContainer</span><span class="token punctuation">(</span><span class="token keyword">for</span><span class="token punctuation">:</span> <span class="token class-name">User</span><span class="token punctuation">.</span><span class="token keyword">self</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>When it comes to editing <code>User</code> objects, we would create a new view called something like <code>EditUserView</code>, then use the <code>@Bindable</code> property wrapper to create bindings for it. So, something like this:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token keyword">struct</span> <span class="token class-name">EditUserView</span><span class="token punctuation">:</span> <span class="token class-name">View</span> <span class="token punctuation">{</span>
    <span class="token attribute atrule">@Bindable</span> <span class="token keyword">var</span> user<span class="token punctuation">:</span> <span class="token class-name">User</span>

    <span class="token keyword">var</span> body<span class="token punctuation">:</span> <span class="token keyword">some</span> <span class="token class-name">View</span> <span class="token punctuation">{</span>
        <span class="token class-name">Form</span> <span class="token punctuation">{</span>
            <span class="token class-name">TextField</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;Name&quot;</span></span><span class="token punctuation">,</span> text<span class="token punctuation">:</span> $user<span class="token punctuation">.</span>name<span class="token punctuation">)</span>
            <span class="token class-name">TextField</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;City&quot;</span></span><span class="token punctuation">,</span> text<span class="token punctuation">:</span> $user<span class="token punctuation">.</span>city<span class="token punctuation">)</span>
            <span class="token class-name">DatePicker</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;Join Date&quot;</span></span><span class="token punctuation">,</span> selection<span class="token punctuation">:</span> $user<span class="token punctuation">.</span>joinDate<span class="token punctuation">)</span>
        <span class="token punctuation">}</span>
        <span class="token punctuation">.</span><span class="token function">navigationTitle</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;Edit User&quot;</span></span><span class="token punctuation">)</span>
        <span class="token punctuation">.</span><span class="token function">navigationBarTitleDisplayMode</span><span class="token punctuation">(</span><span class="token punctuation">.</span>inline<span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>That&#39;s <em>identical</em> to how we used a regular <code>@Observable</code> class, and yet SwiftData still takes care of automatically writing out all our changes to permanent storage – it&#39;s completely transparent to us.</p><p><strong>Important</strong>: If you want to use Xcode&#39;s previews with this, you need to pass a sample object in, which in turn means creating a custom configuration and container. First add an import for SwiftData, then change your preview to this:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token other-directive property">#Preview</span> <span class="token punctuation">{</span>
    <span class="token keyword">do</span> <span class="token punctuation">{</span>
        <span class="token keyword">let</span> config <span class="token operator">=</span> <span class="token class-name">ModelConfiguration</span><span class="token punctuation">(</span>isStoredInMemoryOnly<span class="token punctuation">:</span> <span class="token boolean">true</span><span class="token punctuation">)</span>
        <span class="token keyword">let</span> container <span class="token operator">=</span> <span class="token keyword">try</span> <span class="token class-name">ModelContainer</span><span class="token punctuation">(</span><span class="token keyword">for</span><span class="token punctuation">:</span> <span class="token class-name">User</span><span class="token punctuation">.</span><span class="token keyword">self</span><span class="token punctuation">,</span> configurations<span class="token punctuation">:</span> config<span class="token punctuation">)</span>
        <span class="token keyword">let</span> user <span class="token operator">=</span> <span class="token class-name">User</span><span class="token punctuation">(</span>name<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;Taylor Swift&quot;</span></span><span class="token punctuation">,</span> city<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;Nashville&quot;</span></span><span class="token punctuation">,</span> joinDate<span class="token punctuation">:</span> <span class="token punctuation">.</span>now<span class="token punctuation">)</span>
        <span class="token keyword">return</span> <span class="token class-name">EditUserView</span><span class="token punctuation">(</span>user<span class="token punctuation">:</span> user<span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">modelContainer</span><span class="token punctuation">(</span>container<span class="token punctuation">)</span>
    <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token class-name">Text</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;Failed to create container: </span><span class="token interpolation-punctuation punctuation">\\(</span><span class="token interpolation">error<span class="token punctuation">.</span>localizedDescription</span><span class="token interpolation-punctuation punctuation">)</span><span class="token string">&quot;</span></span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>We could make a really simple user editing app out of this by adding a new user when a button is pressed, then using programmatic navigation to take the app straight to the new user for editing.</p>`,9),N=n("code",null,"ContentView.swift",-1),L=n("code",null,"User",-1),V=n("code",null,"NavigationStack",-1),F=l(`<div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token attribute atrule">@Environment</span><span class="token punctuation">(</span><span class="token punctuation">\\</span><span class="token punctuation">.</span>modelContext<span class="token punctuation">)</span> <span class="token keyword">var</span> modelContext
<span class="token attribute atrule">@Query</span><span class="token punctuation">(</span>sort<span class="token punctuation">:</span> <span class="token punctuation">\\</span><span class="token class-name">User</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span> <span class="token keyword">var</span> users<span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token class-name">User</span><span class="token punctuation">]</span>
<span class="token attribute atrule">@State</span> <span class="token keyword">private</span> <span class="token keyword">var</span> path <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token class-name">User</span><span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Replace the default <code>body</code> property with this:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token class-name">NavigationStack</span><span class="token punctuation">(</span>path<span class="token punctuation">:</span> $path<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token class-name">List</span><span class="token punctuation">(</span>users<span class="token punctuation">)</span> <span class="token punctuation">{</span> user <span class="token keyword">in</span>
        <span class="token class-name">NavigationLink</span><span class="token punctuation">(</span>value<span class="token punctuation">:</span> user<span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token class-name">Text</span><span class="token punctuation">(</span>user<span class="token punctuation">.</span>name<span class="token punctuation">)</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
    <span class="token punctuation">.</span><span class="token function">navigationTitle</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;Users&quot;</span></span><span class="token punctuation">)</span>
    <span class="token punctuation">.</span><span class="token function">navigationDestination</span><span class="token punctuation">(</span><span class="token keyword">for</span><span class="token punctuation">:</span> <span class="token class-name">User</span><span class="token punctuation">.</span><span class="token keyword">self</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> user <span class="token keyword">in</span>
        <span class="token class-name">EditUserView</span><span class="token punctuation">(</span>user<span class="token punctuation">:</span> user<span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>And now we just need a way to add users. If you think about it, adding and editing are very similar, so the easiest thing to do here is to create a new <code>User</code> object with empty properties, insert it into the model context, then immediately navigate to that by adjusting the <code>path</code> property.</p><p>Add this extra modifier below the two navigation modifiers:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token punctuation">.</span>toolbar <span class="token punctuation">{</span>
    <span class="token class-name">Button</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;Add User&quot;</span></span><span class="token punctuation">,</span> systemImage<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;plus&quot;</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">let</span> user <span class="token operator">=</span> <span class="token class-name">User</span><span class="token punctuation">(</span>name<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;&quot;</span></span><span class="token punctuation">,</span> city<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;&quot;</span></span><span class="token punctuation">,</span> joinDate<span class="token punctuation">:</span> <span class="token punctuation">.</span>now<span class="token punctuation">)</span>
        modelContext<span class="token punctuation">.</span><span class="token function">insert</span><span class="token punctuation">(</span>user<span class="token punctuation">)</span>
        path <span class="token operator">=</span> <span class="token punctuation">[</span>user<span class="token punctuation">]</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>And that works! In fact, it&#39;s pretty much the same approach Apple&#39;s own Notes app takes, although they add the extra step of automatically deleting the note if you exit the editing view without actually adding any text.</p><p>As you can see, editing with SwiftData objects is no different from editing regular <code>@Observable</code> classes – just with the added bonus that all our data is loaded and saved neatly!</p><p>:::</p><h3 id="filtering-query-using-predicate" tabindex="-1"><a class="header-anchor" href="#filtering-query-using-predicate"><span>Filtering <code>@Query</code> using Predicate</span></a></h3><p>::: detail Filtering @Query using Predicate</p>`,11),Q=l(`<p>You&#39;ve already seen how <code>@Query</code> can be used to sort SwiftData objects in a particular order, but it can also be used to filter that data using a <em>predicate</em> – a series of tests that get applied to your data, to decide what to return.</p><p>The syntax for this is a little odd at first, mostly because this is actually <em>another</em> macro behind the scenes - Swift converts our predicate code into a series of rules it can apply to the underlying database that stores all of SwiftData&#39;s objects.</p><p>Let&#39;s start with something simple, using the same <code>User</code> model we used previously:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token attribute atrule">@Model</span>
<span class="token keyword">class</span> <span class="token class-name">User</span> <span class="token punctuation">{</span>
    <span class="token keyword">var</span> name<span class="token punctuation">:</span> <span class="token class-name">String</span>
    <span class="token keyword">var</span> city<span class="token punctuation">:</span> <span class="token class-name">String</span>
    <span class="token keyword">var</span> joinDate<span class="token punctuation">:</span> <span class="token class-name">Date</span>

    <span class="token keyword">init</span><span class="token punctuation">(</span>name<span class="token punctuation">:</span> <span class="token class-name">String</span><span class="token punctuation">,</span> city<span class="token punctuation">:</span> <span class="token class-name">String</span><span class="token punctuation">,</span> joinDate<span class="token punctuation">:</span> <span class="token class-name">Date</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">self</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name
        <span class="token keyword">self</span><span class="token punctuation">.</span>city <span class="token operator">=</span> city
        <span class="token keyword">self</span><span class="token punctuation">.</span>joinDate <span class="token operator">=</span> joinDate
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Now we can add a couple of properties to <code>ContentView</code> that can show all the users we have:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token attribute atrule">@Environment</span><span class="token punctuation">(</span><span class="token punctuation">\\</span><span class="token punctuation">.</span>modelContext<span class="token punctuation">)</span> <span class="token keyword">var</span> modelContext
<span class="token attribute atrule">@Query</span><span class="token punctuation">(</span>sort<span class="token punctuation">:</span> <span class="token punctuation">\\</span><span class="token class-name">User</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span> <span class="token keyword">var</span> users<span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token class-name">User</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>And finally, we can show all those users in a list, and we&#39;ll also add a button to add some sample data easily:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token class-name">NavigationStack</span> <span class="token punctuation">{</span>
    <span class="token class-name">List</span><span class="token punctuation">(</span>users<span class="token punctuation">)</span> <span class="token punctuation">{</span> user <span class="token keyword">in</span>
        <span class="token class-name">Text</span><span class="token punctuation">(</span>user<span class="token punctuation">.</span>name<span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
    <span class="token punctuation">.</span><span class="token function">navigationTitle</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;Users&quot;</span></span><span class="token punctuation">)</span>
    <span class="token punctuation">.</span>toolbar <span class="token punctuation">{</span>
        <span class="token class-name">Button</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;Add Samples&quot;</span></span><span class="token punctuation">,</span> systemImage<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;plus&quot;</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token keyword">let</span> first <span class="token operator">=</span> <span class="token class-name">User</span><span class="token punctuation">(</span>name<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;Ed Sheeran&quot;</span></span><span class="token punctuation">,</span> city<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;London&quot;</span></span><span class="token punctuation">,</span> joinDate<span class="token punctuation">:</span> <span class="token punctuation">.</span>now<span class="token punctuation">.</span><span class="token function">addingTimeInterval</span><span class="token punctuation">(</span><span class="token number">86400</span> <span class="token operator">*</span> <span class="token operator">-</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
            <span class="token keyword">let</span> second <span class="token operator">=</span> <span class="token class-name">User</span><span class="token punctuation">(</span>name<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;Rosa Diaz&quot;</span></span><span class="token punctuation">,</span> city<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;New York&quot;</span></span><span class="token punctuation">,</span> joinDate<span class="token punctuation">:</span> <span class="token punctuation">.</span>now<span class="token punctuation">.</span><span class="token function">addingTimeInterval</span><span class="token punctuation">(</span><span class="token number">86400</span> <span class="token operator">*</span> <span class="token operator">-</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
            <span class="token keyword">let</span> third <span class="token operator">=</span> <span class="token class-name">User</span><span class="token punctuation">(</span>name<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;Roy Kent&quot;</span></span><span class="token punctuation">,</span> city<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;London&quot;</span></span><span class="token punctuation">,</span> joinDate<span class="token punctuation">:</span> <span class="token punctuation">.</span>now<span class="token punctuation">.</span><span class="token function">addingTimeInterval</span><span class="token punctuation">(</span><span class="token number">86400</span> <span class="token operator">*</span> <span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
            <span class="token keyword">let</span> fourth <span class="token operator">=</span> <span class="token class-name">User</span><span class="token punctuation">(</span>name<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;Johnny English&quot;</span></span><span class="token punctuation">,</span> city<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;London&quot;</span></span><span class="token punctuation">,</span> joinDate<span class="token punctuation">:</span> <span class="token punctuation">.</span>now<span class="token punctuation">.</span><span class="token function">addingTimeInterval</span><span class="token punctuation">(</span><span class="token number">86400</span> <span class="token operator">*</span> <span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">)</span>

            modelContext<span class="token punctuation">.</span><span class="token function">insert</span><span class="token punctuation">(</span>first<span class="token punctuation">)</span>
            modelContext<span class="token punctuation">.</span><span class="token function">insert</span><span class="token punctuation">(</span>second<span class="token punctuation">)</span>
            modelContext<span class="token punctuation">.</span><span class="token function">insert</span><span class="token punctuation">(</span>third<span class="token punctuation">)</span>
            modelContext<span class="token punctuation">.</span><span class="token function">insert</span><span class="token punctuation">(</span>fourth<span class="token punctuation">)</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Tip: Those join dates represent some number of days in the past of future, which gives us some interesting data to work with.</p><p>When working with sample data like this, it&#39;s helpful to be able to delete existing data before adding the sample data. To do that, add the following code before the <code>let first =</code> line:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token keyword">try</span><span class="token operator">?</span> modelContext<span class="token punctuation">.</span><span class="token function">delete</span><span class="token punctuation">(</span>model<span class="token punctuation">:</span> <span class="token class-name">User</span><span class="token punctuation">.</span><span class="token keyword">self</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>That tells SwiftData to tell all existing model objects of the the type <code>User</code>, which means the database is clear before we add the sample users.</p><p>To finish our little sample app, we just need to make sure the <code>App</code> struct uses the <code>modelContainer()</code> modifier to set up SwiftData correctly:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token class-name">WindowGroup</span> <span class="token punctuation">{</span>
    <span class="token class-name">ContentView</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
<span class="token punctuation">.</span><span class="token function">modelContainer</span><span class="token punctuation">(</span><span class="token keyword">for</span><span class="token punctuation">:</span> <span class="token class-name">User</span><span class="token punctuation">.</span><span class="token keyword">self</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Now go ahead and run the app, then press the + button to insert four users.</p><p>You can see they appear in alphabetical order, because that&#39;s what we asked for in our <code>@Query</code> property.</p><p>Now let&#39;s try filtering that data, so that we only show users whose name contains a capital R. To do this we pass a <code>filter</code> parameter into <code>@Query</code>, like this:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token attribute atrule">@Query</span><span class="token punctuation">(</span>filter<span class="token punctuation">:</span> <span class="token other-directive property">#Predicate</span><span class="token operator">&lt;</span><span class="token class-name">User</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span> user <span class="token keyword">in</span>
    user<span class="token punctuation">.</span>name<span class="token punctuation">.</span><span class="token function">contains</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;R&quot;</span></span><span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">,</span> sort<span class="token punctuation">:</span> <span class="token punctuation">\\</span><span class="token class-name">User</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span> <span class="token keyword">var</span> users<span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token class-name">User</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Let&#39;s break that down:</p><ol><li>The filter starts with <code>#Predicate&lt;User&gt;</code>, which means we&#39;re writing a predicate (a fancy word for a test we&#39;re going to apply).</li><li>That predicate gives us a single user instance to check. In practice that will be called once for each user loaded by SwiftData, and we need to return true if that user should be included in the results.</li><li>Our test checks whether the user&#39;s name contains the capital letter R. If it does, the user will be included in the results, otherwise they won&#39;t.</li></ol><p>So, when you run the code now you&#39;ll see that both Rosa and Roy appear in our list, but Ed and Johnny are left off because their names don&#39;t contain a capital R. The <code>contains()</code> method is case-sensitive: it considers capital R and lowercase R to be difference, which is why it didn&#39;t find the &quot;r&quot; in &quot;Ed Sheeran&quot;.</p><p>That works great for a simple test of predicates, but it&#39;s very rare users actually care about capital letters – they usually just want to write a few letters, and look for that match anywhere in the results, ignoring case.</p><p>For this purpose, iOS gives us a separate method <code>localizedStandardContains()</code>. This also takes a string to search for, except it automatically ignores letter case, so it&#39;s a much better option when you&#39;re trying to filter by user text.</p><p>Here&#39;s how it looks:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token attribute atrule">@Query</span><span class="token punctuation">(</span>filter<span class="token punctuation">:</span> <span class="token other-directive property">#Predicate</span><span class="token operator">&lt;</span><span class="token class-name">User</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span> user <span class="token keyword">in</span>
    user<span class="token punctuation">.</span>name<span class="token punctuation">.</span><span class="token function">localizedStandardContains</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;R&quot;</span></span><span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">,</span> sort<span class="token punctuation">:</span> <span class="token punctuation">\\</span><span class="token class-name">User</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span> <span class="token keyword">var</span> users<span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token class-name">User</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>In our little test data that means we&#39;ll see three out of the four users, because those three have a letter &quot;r&quot; somewhere in their name.</p><p>Now let&#39;s go a step further: let&#39;s upgrade our filter so that it matches people who have an &quot;R&quot; in their name and who live in London:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token attribute atrule">@Query</span><span class="token punctuation">(</span>filter<span class="token punctuation">:</span> <span class="token other-directive property">#Predicate</span><span class="token operator">&lt;</span><span class="token class-name">User</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span> user <span class="token keyword">in</span>
    user<span class="token punctuation">.</span>name<span class="token punctuation">.</span><span class="token function">localizedStandardContains</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;R&quot;</span></span><span class="token punctuation">)</span> <span class="token operator">&amp;&amp;</span>
    user<span class="token punctuation">.</span>city <span class="token operator">==</span> <span class="token string-literal"><span class="token string">&quot;London&quot;</span></span>
<span class="token punctuation">}</span><span class="token punctuation">,</span> sort<span class="token punctuation">:</span> <span class="token punctuation">\\</span><span class="token class-name">User</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span> <span class="token keyword">var</span> users<span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token class-name">User</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>That uses Swift&#39;s &quot;logical and&quot; operator, which means both sides of the condition must be true in order for the whole condition to be true – the user&#39;s name must contain an &quot;R&quot; <em>and</em> they must live in London.</p><p>If we only had the first check for the letter R, then Ed, Rosa, and Roy would match. If we only had the second check for living in London, then Ed, xxxxxx, and Johnny would match. Putting <em>both</em> together means that only Ed and Roy match, because they are the only two with an R somewhere in their name who also live in London.</p><p>You can add more and more checks like this, but using <code>&amp;&amp;</code> gets a bit confusing. Fortunately, these predicates support a <em>limited subset</em> of Swift expressions that make reading a little easier.</p><p>For example, we could rewrite our current predicate to this:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token attribute atrule">@Query</span><span class="token punctuation">(</span>filter<span class="token punctuation">:</span> <span class="token other-directive property">#Predicate</span><span class="token operator">&lt;</span><span class="token class-name">User</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span> user <span class="token keyword">in</span>
    <span class="token keyword">if</span> user<span class="token punctuation">.</span>name<span class="token punctuation">.</span><span class="token function">localizedStandardContains</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;R&quot;</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">if</span> user<span class="token punctuation">.</span>city <span class="token operator">==</span> <span class="token string-literal"><span class="token string">&quot;London&quot;</span></span> <span class="token punctuation">{</span>
            <span class="token keyword">return</span> <span class="token boolean">true</span>
        <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
            <span class="token keyword">return</span> <span class="token boolean">false</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token boolean">false</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">,</span> sort<span class="token punctuation">:</span> <span class="token punctuation">\\</span><span class="token class-name">User</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span> <span class="token keyword">var</span> users<span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token class-name">User</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Now, you might be thinking that&#39;s a little verbose – that could remove both <code>else</code> blocks and just end with <code>return true</code>, because if the user actually matched the predicate the <code>return true</code> would already have been hit.</p><p>Here&#39;s how that would look:</p><div class="language-swift line-numbers-mode" data-ext="swift" data-title="swift"><pre class="language-swift"><code><span class="token attribute atrule">@Query</span><span class="token punctuation">(</span>filter<span class="token punctuation">:</span> <span class="token other-directive property">#Predicate</span><span class="token operator">&lt;</span><span class="token class-name">User</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span> user <span class="token keyword">in</span>
    <span class="token keyword">if</span> user<span class="token punctuation">.</span>name<span class="token punctuation">.</span><span class="token function">localizedStandardContains</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;R&quot;</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">if</span> user<span class="token punctuation">.</span>city <span class="token operator">==</span> <span class="token string-literal"><span class="token string">&quot;London&quot;</span></span> <span class="token punctuation">{</span>
            <span class="token keyword">return</span> <span class="token boolean">true</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">return</span> <span class="token boolean">false</span>
<span class="token punctuation">}</span><span class="token punctuation">,</span> sort<span class="token punctuation">:</span> <span class="token punctuation">\\</span><span class="token class-name">User</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span> <span class="token keyword">var</span> users<span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token class-name">User</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Sadly that code isn&#39;t actually valid, because even though it looks like we&#39;re executing pure Swift code it&#39;s important you remember that doesn&#39;t actually happen – the <code>#Predicate</code> macro actually rewrites our code to be a series of tests it can apply on the database, which <em>doesn&#39;t</em> use Swift internally.</p><p>To see what&#39;s happening internally, press undo a few times to get the original version with two <code>else</code> blocks. Now right-click on <code>#Predicate</code> and select Expand Macro, and you&#39;ll see a huge amount of code appears. Remember, <em>this</em> is the actual code that gets built and run – it&#39;s what our <code>#Predicate</code> gets converted into.</p><p>So, that&#39;s just a little of how <code>#Predicate</code> works, and why some predicates you might try just don&#39;t quite work how you expect – this stuff looks easy, but it&#39;s really complex behind the scenes!</p><p>:::</p><hr>`,41);function A(d,B){const e=t("router-link"),o=t("VPCard"),u=t("VidStack"),r=t("FontIcon"),k=t("TagLinks");return h(),w("div",null,[n("h1",g,[n("a",b,[n("span",null,v(d.$frontmatter.title)+" 관련",1)])]),n("nav",y,[n("ul",null,[n("li",null,[a(e,{to:"#project-12-part-1"},{default:p(()=>[s("Project 12, part 1")]),_:1}),n("ul",null,[n("li",null,[a(e,{to:"#swiftdata-introduction"},{default:p(()=>[s("SwiftData: Introduction")]),_:1})]),n("li",null,[a(e,{to:"#editing-swiftdata-model-objects"},{default:p(()=>[s("Editing SwiftData model objects")]),_:1})]),n("li",null,[a(e,{to:"#filtering-query-using-predicate"},{default:p(()=>[s("Filtering @Query using Predicate")]),_:1})])])])])]),q,S,a(o,i(c({title:"100 Days of SwiftUI - Day 57",desc:"Project 12, part 1",link:"https://www.hackingwithswift.com/100/swiftui/57",logo:"https://www.hackingwithswift.com/favicon-96x96.png",background:"rgba(54,94,226,0.2)"})),null,16),x,D,_,j,U,a(o,i(c({title:"100 Days of SwiftUI - Day 57 - SwiftData: Introduction",desc:"SwiftData: Introduction",link:"https://www.hackingwithswift.com/books/ios-swiftui/swiftdata-introduction",logo:"https://www.hackingwithswift.com/favicon-96x96.png",background:"rgba(54,94,226,0.2)"})),null,16),I,a(o,i(c({title:"100 Days of SwiftUI - Day 57 - Editing SwiftData model objects",desc:"Editing SwiftData model objects",link:"https://www.hackingwithswift.com/books/ios-swiftui/editing-swiftdata-model-objects",logo:"https://www.hackingwithswift.com/favicon-96x96.png",background:"rgba(54,94,226,0.2)"})),null,16),a(u,{src:"youtube/jnW5m1qUINA"}),T,C,n("p",null,[s("To demonstrate this, we could create a simple "),P,s(" class with a handful of properties. Create a new file called "),a(r,{icon:"fa-brands fa-swift"}),R,s(", add an import at the top for SwiftData, then give it this code:")]),E,n("p",null,[s("Let's build this step by step. First, open "),a(r,{icon:"fa-brands fa-swift"}),N,s(" and an import for SwiftData, then add properties to get access to the model context, load all our "),L,s(" objects, then store a path we can bind to a "),V,s(":")]),F,a(o,i(c({title:"100 Days of SwiftUI - Day 57 - Filtering @Query using Predicate",desc:"Filtering @Query using Predicate",link:"https://www.hackingwithswift.com/books/ios-swiftui/filtering-query-using-predicate",logo:"https://www.hackingwithswift.com/favicon-96x96.png",background:"rgba(54,94,226,0.2)"})),null,16),a(u,{src:"youtube/bV5KnqMHXe0"}),Q,a(k)])}const O=m(f,[["render",A],["__file","57.html.vue"]]),W=JSON.parse('{"path":"/swift/100-days-of-swiftui/57.html","title":"Day 57","lang":"ko-KR","frontmatter":{"lang":"ko-KR","title":"Day 57","description":"100 Days of SwiftUI > Day 57","category":["Swift"],"tag":["crashcourse","paul-hudson","swift","swiftui","hacking-with-swift","xcode","appstore"],"head":[[{"meta":null},{"property":"og:title","content":"100 Days of SwiftUI > Day 57"},{"property":"og:description","content":"Day 57"},{"property":"og:url","content":"https://chanhi2000.github.io/crashcourse/swift/100-days-of-swiftui/57.html"}]]},"headers":[{"level":2,"title":"Project 12, part 1","slug":"project-12-part-1","link":"#project-12-part-1","children":[{"level":3,"title":"SwiftData: Introduction","slug":"swiftdata-introduction","link":"#swiftdata-introduction","children":[]},{"level":3,"title":"Editing SwiftData model objects","slug":"editing-swiftdata-model-objects","link":"#editing-swiftdata-model-objects","children":[]},{"level":3,"title":"Filtering @Query using Predicate","slug":"filtering-query-using-predicate","link":"#filtering-query-using-predicate","children":[]}]}],"git":{},"readingTime":{"minutes":7.63,"words":2290},"filePathRelative":"swift/100-days-of-swiftui/57.md","excerpt":"\\n\\n<hr>\\n<h2>Project 12, part 1</h2>\\n"}');export{O as comp,W as data};
